use std::sync::{Arc, Mutex};

struct Connection {
    id: String,
}

impl Connection {
    fn new(id: String) -> Self {
        Connection { id }
    }

    fn open(&self) -> Result<(), String> {
        // Simulate a connection error
        Err("Connection failed".to_string())
    }
}

struct ConnectionGuard {
    conn: Arc<Mutex<Connection>>,
}

impl Drop for ConnectionGuard {
    fn drop(&mut self) {
        println!("Closing connection {}", self.conn.lock().unwrap().id);
    }
}

fn main() {
    let conn = Arc::new(Mutex::new(Connection::new("12345".to_string())));

    // Attempt to open the connection, but handle errors!
    if let Err(e) = conn.lock().unwrap().open() {
        eprintln!("Failed to open connection: {}", e);
    }

    drop(ConnectionGuard { conn: conn.clone() });
